def flattened_syllabus():
    return [
        dict(subject=subject, grade=grade, title=chapter["title"], subtopics=chapter["subtopics"])
        for subject, grades in SYLLABUS.items()
        for grade, chapters in grades.items()
        for chapter in chapters
    ]
